def seed_mjml_components(apps, schema_editor):
    MjmlComponent = apps.get_model('emails', 'MjmlComponent')
    for order, (name, placement, markup) in enumerate(COMPONENTS, start=10):
        MjmlComponent.objects.get_or_create(
            name=name,
            defaults={'placement': placement, 'mjml_markup': markup, 'order': order * 10},
        )


def unseed_mjml_components(apps, schema_editor):
    MjmlComponent = apps.get_model('emails', 'MjmlComponent')
    names = [name for name, _, _ in COMPONENTS]
    MjmlComponent.objects.filter(name__in=names).delete()


